module parallel2serial(
    input clk,
    input rst_n,
    input [3:0] d,
    output reg valid_out,
    output reg dout
);

reg [1:0] counter;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        counter <= 0;
        valid_out <= 0;
        dout <= 0;
    end else begin
        if (counter == 0) begin
            dout <= d[3];
            valid_out <= 1;
        end else if (counter == 1) begin
            dout <= d[2];
        end else if (counter == 2) begin
            dout <= d[1];
        end else if (counter == 3) begin
            dout <= d[0];
            valid_out <= 0;
        end

        counter <= counter + 1;
        if (counter == 3)
            counter <= 0;
    end
end

endmodule
